=Parse the following payload into the defined JSON schema. Ensure the Discussion Points are dense and technical, and the Milestones accurately reflect the project roadmap.

### DATA SOURCE:
{{ $json.narrative_context }}
{{ $json.structured_tabular_data }}

### REFERENCE:
Subject: {{ $json.metadata.subject }}
Date: {{ $json.metadata.date }}

parameters.jsCode:
return items.map(item => {
  try {
    const rawOutput = item.json.output || "";

    const jsonStart = rawOutput.indexOf("{");
    const jsonEnd = rawOutput.lastIndexOf("}") + 1;

    if (jsonStart === -1 || jsonEnd === 0) {
      throw new Error("No JSON object found");
    }

    let jsonText = rawOutput.substring(jsonStart, jsonEnd)
      .replace(/```json/g, "")
      .replace(/```/g, "")
      .trim();

    // Repair raw line breaks inside JSON strings
    let repaired = "";
    let inString = false;
    let escaped = false;

    for (const char of jsonText) {
      if (escaped) {
        repaired += char;
        escaped = false;
        continue;
      }

      if (char === "\\") {
        repaired += char;
        escaped = true;
        continue;
      }

      if (char === '"') {
        repaired += char;
        inString = !inString;
        continue;
      }

      if (inString && char === "\n") {
        repaired += "\\n";
        continue;
      }

      if (inString && char === "\r") {
        repaired += "\\r";
        continue;
      }

      repaired += char;
    }

    const aiData = JSON.parse(repaired);

    return {
      json: {
        metadata: aiData.metadata,
        discussion_points: aiData.discussion_points,
        milestones: aiData.milestones
      }
    };

  } catch (error) {
    return {
      json: {
        error: "JSON Parsing Failed",
        message: error.message,
        raw: item.json.output
      }
    };
  }
});

// This script extracts tabular data, narrative context, and builds a clean email-only Airtable Formula
const EXCLUDED_EMAILS = [
  "placements.sv@scalevirtually.com",
  "ace@scalevirtually.com",
  "ck@scalevirtually.com",
  "bam@scalevirtually.com",
  "karlo@scalevirtually.com"
];

const simplified_output = [];

for (const item of $input.all()) {
  const json_content = item.json;

  // 1. Extract and Clean Email Participants
  const fromEmail = json_content.from?.value?.[0]?.address?.toLowerCase() || "";
  const toEmails = (json_content.to?.value || []).map(p => p.address.toLowerCase());
  const ccEmails = (json_content.cc?.value || []).map(p => p.address.toLowerCase());

  // 2. Internal Exclusion Logic
  const primaryTo = toEmails[0] || "";
  if (EXCLUDED_EMAILS.includes(primaryTo)) continue;

  const hasExternalTo = toEmails.some(addr => !EXCLUDED_EMAILS.includes(addr));
  if (!hasExternalTo) continue;

  // 3. Metadata & Participant Flattening
  const subject = json_content.subject || "No Subject";
  const allParticipants = [...new Set([fromEmail, ...toEmails, ...ccEmails])]
    .filter(e => e !== "")
    .map(e => e.trim());

  // 4. Construct Clean Airtable Formula (Emails Only)
  const emailConditions = allParticipants.map(emailAddr => {
    return `FIND('${emailAddr}', LOWER(ARRAYJOIN({Email (from Client)}, ' '))), FIND('${emailAddr}', LOWER(ARRAYJOIN({POC Primary email}, ' ')))`;
  });

  // Removed the {PDEV STAGE} logic here as requested
  const airtable_formula = `OR(${emailConditions.join(", ")})`;

  // 5. Extract Narrative Context
  let text_body = json_content.text || "";
  let narrative_context = text_body.split(/thanks and regards|best regards|--/i)[0].trim();

  // 6. Extract Structural Data (HTML Tables)
  let html_body = json_content.html || "";
  let table_data = [];
  const cell_matches = html_body.match(/<td[^>]*>(.*?)<\/td>/gi);
  if (cell_matches) {
    table_data = cell_matches.map(cell => cell.replace(/<[^>]*>/g, '').trim()).filter(text => text !== "");
  }

  simplified_output.push({
    json: {
      metadata: {
          from: fromEmail,
          to_primary: primaryTo,
          subject: subject,
          date: json_content.date,
          participants: allParticipants
      },
      airtable_formula: airtable_formula,
      narrative_context: narrative_context,
      structured_tabular_data: table_data.join(" | "),
      is_hybrid_payload: table_data.length > 0 && narrative_context.length > 50
    }
  });
}

return simplified_output;

return items.map(item => {
  let raw = item.json.Milestones || item.json.milestones || [];

  // If Milestones is a JSON string, parse it
  if (typeof raw === 'string') {
    try {
      raw = JSON.parse(raw);
    } catch (error) {
      raw = [];
    }
  }

  // If still not an array, force it to empty array
  if (!Array.isArray(raw)) {
    raw = [];
  }

  const milestonesText = raw
    .map((m, index) => {
      const date = m.date || 'TBD';
      const task = String(m.task || '')
        .replace(/\*\*/g, '')
        .trim();

      return `${index + 1}. [${date}] ${task}`;
    })
    .join('\n');

  return {
    json: {
      ...item.json,

      // Create a NEW clean field
      Milestones_Text: milestonesText
    }
  };
});

